package main

import (
	"fmt"
	"go/ast"
	"go/parser"
	"go/token"
	"os"
	"path/filepath"
	"strings"
)

var root = "/Users/luc/Developer/luuuc/oss/sense-benchmark/baseline/teleport"

type ifaceInfo struct {
	pkgDir  string
	name    string
	pos     string
	methods []string
	embeds  []string
}

var ifaces = map[string]*ifaceInfo{} // key pkgDir + "." + name

// storage vocabulary: methods that only the cluster-state store / cache expose
var vocab = []string{
	"NewWatcher", "GetCertAuthority", "GetCertAuthorities", "GetClusterName",
	"GetClusterNetworkingConfig", "GetSessionRecordingConfig", "GetAuthPreference",
	"GetRole", "GetRoles", "GetNodes", "GetNode", "ListResources", "GetProxies",
	"GetRemoteClusters", "GetRemoteCluster", "GetApplicationServers", "GetAppServers",
	"GetDatabaseServers", "GetKubernetesServers", "GetWindowsDesktops",
	"GetClusterAuditConfig", "GetNetworkRestrictions", "GetUser", "GetUsers",
	"GetToken", "GetTokens", "GetLocks", "GetLock", "GetReverseTunnels",
	"GetAuthServers", "GetNamespace", "GetSAMLIdPServiceProviders", "GetUserGroups",
	"GetInstallers", "GetUIConfig", "GetAccessRequests", "GetPluginData",
	"GetSessionTracker", "GetAllTunnelConnections", "GetTunnelConnections",
	"GetKubernetesCluster", "GetApps", "GetApp", "GetDatabases", "GetDatabase",
	"GetIntegration", "ListIntegrations", "GetStaticTokens", "GetClusterAccessGraphConfig",
	"GetAutoUpdateConfig", "GetAutoUpdateVersion", "GetAutoUpdateAgentRollout",
	"GetGitServer", "ListGitServers", "GetSAMLConnector", "GetOIDCConnector",
	"GetGithubConnector", "GetAccessList", "ListAccessLists", "GetHealthCheckConfig",
	"ListHealthCheckConfigs", "GetClusterMaintenanceConfig", "ListUnifiedResources",
	"GetVnetConfig", "GetDynamicWindowsDesktop", "GetRelayServer", "ListRelayServers",
	"GetSessionRecordingConfig", "GetRecordingEncryption",
}
var vocabSet = map[string]bool{}

// package-qualified types that ARE the storage / its cache / known narrowed views
func isKnownStorageType(s string) string {
	// strip pointers/slices
	t := strings.TrimLeft(s, "*[]")
	switch {
	case strings.HasPrefix(t, "authclient.") && strings.Contains(t, "AccessPoint"):
		return "authclient AccessPoint"
	case t == "cache.Cache" || t == "*cache.Cache":
		return "lib/cache.Cache"
	case t == "auth.Services" || t == "Services" :
		return "auth.Services"
	case strings.HasPrefix(t, "services.") :
		return "lib/services iface"
	case strings.HasPrefix(t, "local."):
		return "lib/services/local"
	case strings.HasPrefix(t, "backend.") && (strings.Contains(t,"Backend")):
		return "lib/backend"
	}
	return ""
}

func main() {
	for _, k := range vocab { vocabSet[k] = true }
	fset := token.NewFileSet()
	files := map[string][]*ast.File{} // dir -> files
	filepath.Walk(root, func(p string, info os.FileInfo, err error) error {
		if err != nil { return nil }
		if info.IsDir() {
			b := info.Name()
			if b == "vendor" || b == "node_modules" || b == ".git" || b == "web" || b == "gen" { return filepath.SkipDir }
			return nil
		}
		if !strings.HasSuffix(p, ".go") || strings.HasSuffix(p, "_test.go") { return nil }
		f, e := parser.ParseFile(fset, p, nil, parser.ParseComments)
		if e != nil { return nil }
		d := filepath.Dir(p)
		files[d] = append(files[d], f)
		return nil
	})

	// pass 1: interfaces
	for d, fs := range files {
		for _, f := range fs {
			ast.Inspect(f, func(n ast.Node) bool {
				ts, ok := n.(*ast.TypeSpec); if !ok { return true }
				it, ok := ts.Type.(*ast.InterfaceType); if !ok { return true }
				ii := &ifaceInfo{pkgDir: d, name: ts.Name.Name, pos: rel(fset.Position(ts.Pos()).String())}
				for _, m := range it.Methods.List {
					if len(m.Names) > 0 { ii.methods = append(ii.methods, m.Names[0].Name) } else {
						ii.embeds = append(ii.embeds, exprStr(m.Type))
					}
				}
				ifaces[d+"."+ts.Name.Name] = ii
				return true
			})
		}
	}

	// determine storage-shaped interfaces (transitive over embeds within same dir)
	shaped := map[string]string{}
	var eval func(key string, depth int) string
	eval = func(key string, depth int) string {
		if depth > 6 { return "" }
		ii := ifaces[key]; if ii == nil { return "" }
		if r, ok := shaped[key]; ok { return r }
		for _, m := range ii.methods { if vocabSet[m] { shaped[key]="method "+m; return shaped[key] } }
		for _, e := range ii.embeds {
			if k := isKnownStorageType(e); k != "" { shaped[key]="embeds "+e; return shaped[key] }
			if !strings.Contains(e, ".") {
				if r := eval(ii.pkgDir+"."+e, depth+1); r != "" { shaped[key]="embeds "+e; return shaped[key] }
			}
		}
		return ""
	}
	for k := range ifaces { eval(k, 0) }

	// pass 2: struct fields
	type hit struct{ pos, structName, field, typ, why string }
	var hits []hit
	for d, fs := range files {
		for _, f := range fs {
			ast.Inspect(f, func(n ast.Node) bool {
				ts, ok := n.(*ast.TypeSpec); if !ok { return true }
				st, ok := ts.Type.(*ast.StructType); if !ok { return true }
				for _, fl := range st.Fields.List {
					typ := exprStr(fl.Type)
					base := strings.TrimLeft(typ, "*[]")
					why := ""
					if k := isKnownStorageType(typ); k != "" { why = k }
					if why == "" && !strings.Contains(base, ".") {
						if r, ok := shaped[d+"."+base]; ok { why = "local iface " + base + " (" + r + ") @ " + ifaces[d+"."+base].pos }
					}
					if why == "" && strings.Contains(base, ".") {
						// cross-package local-ish interface: resolve by name across all dirs
						parts := strings.SplitN(base, ".", 2)
						for k, ii := range ifaces {
							if ii.name == parts[1] && strings.HasSuffix(ii.pkgDir, "/"+parts[0]) {
								if r, ok := shaped[k]; ok { why = "iface " + base + " (" + r + ") @ " + ii.pos }
							}
						}
					}
					if why == "" { continue }
					name := ""
					if len(fl.Names) > 0 { name = fl.Names[0].Name } else { name = "<embedded>" }
					hits = append(hits, hit{rel(fset.Position(fl.Pos()).String()), ts.Name.Name, name, typ, why})
				}
				return true
			})
		}
	}
	for _, h := range hits {
		fmt.Printf("%s\t%s.%s\t%s\t%s\n", h.pos, h.structName, h.field, h.typ, h.why)
	}
}

func rel(p string) string { return strings.TrimPrefix(p, root+"/") }

func exprStr(e ast.Expr) string {
	switch t := e.(type) {
	case *ast.Ident: return t.Name
	case *ast.StarExpr: return "*" + exprStr(t.X)
	case *ast.SelectorExpr: return exprStr(t.X) + "." + t.Sel.Name
	case *ast.ArrayType: return "[]" + exprStr(t.Elt)
	case *ast.MapType: return "map[" + exprStr(t.Key) + "]" + exprStr(t.Value)
	case *ast.IndexExpr: return exprStr(t.X) + "[" + exprStr(t.Index) + "]"
	case *ast.FuncType: return "func"
	case *ast.ChanType: return "chan"
	case *ast.InterfaceType: return "interface{}"
	case *ast.StructType: return "struct{}"
	case *ast.Ellipsis: return "..."
	}
	return "?"
}
EOF
