package main

import (
	"fmt"
	"go/ast"
	"go/types"
	"os"
	"strings"

	"golang.org/x/tools/go/packages"
)

const root = "/Users/luc/Developer/luuuc/oss/sense-benchmark/baseline/teleport"

func main() {
	cfg := &packages.Config{
		Mode: packages.NeedName | packages.NeedFiles | packages.NeedSyntax | packages.NeedTypes | packages.NeedTypesInfo | packages.NeedDeps | packages.NeedImports,
		Dir:  root,
		Tests: false,
	}
	pkgs, err := packages.Load(cfg, "./lib/...", "./tool/...", "./integrations/...")
	if err != nil { fmt.Fprintln(os.Stderr, err); os.Exit(1) }
	fmt.Fprintf(os.Stderr, "loaded %d pkgs\n", len(pkgs))

	// find concrete storage types
	var targets []struct{ name string; t types.Type }
	add := func(pkgpath, name string, ptr bool) {
		for _, p := range pkgs {
			if p.Types == nil || p.Types.Path() != pkgpath { continue }
			o := p.Types.Scope().Lookup(name)
			if o == nil { return }
			t := o.Type()
			if ptr { t = types.NewPointer(t) }
			targets = append(targets, struct{ name string; t types.Type }{pkgpath + "." + name, t})
			return
		}
	}
	add("github.com/gravitational/teleport/lib/cache", "Cache", true)
	add("github.com/gravitational/teleport/lib/auth", "Services", true)
	add("github.com/gravitational/teleport/lib/auth", "Server", true)
	for _, t := range targets { fmt.Fprintf(os.Stderr, "target %s\n", t.name) }

	// every named interface type declared in these packages
	type ifc struct{ obj *types.TypeName; sat []string }
	sat := map[*types.TypeName][]string{}
	seen := map[*types.TypeName]bool{}
	packages.Visit(pkgs, nil, func(p *packages.Package) {
		if p.Types == nil { return }
		if !strings.HasPrefix(p.Types.Path(), "github.com/gravitational/teleport") { return }
		sc := p.Types.Scope()
		for _, n := range sc.Names() {
			tn, ok := sc.Lookup(n).(*types.TypeName); if !ok { continue }
			if seen[tn] { continue }; seen[tn] = true
			it, ok := tn.Type().Underlying().(*types.Interface); if !ok { continue }
			if it.NumMethods() == 0 { continue }
			for _, tg := range targets {
				if types.Implements(tg.t, it) { sat[tn] = append(sat[tn], tg.name) }
			}
		}
	})
	fmt.Fprintf(os.Stderr, "satisfied interfaces: %d\n", len(sat))
	satNames := map[string][]string{}
	for tn, v := range sat { satNames[tn.Pkg().Path()+"."+tn.Name()] = v }

	// struct fields typed with such an interface
	for _, p := range pkgs {
		if p.Types == nil { continue }
		for i, f := range p.Syntax {
			fname := p.CompiledGoFiles[i]
			if strings.HasSuffix(fname, "_test.go") { continue }
			ast.Inspect(f, func(n ast.Node) bool {
				ts, ok := n.(*ast.TypeSpec); if !ok { return true }
				st, ok := ts.Type.(*ast.StructType); if !ok { return true }
				for _, fl := range st.Fields.List {
					tv := p.TypesInfo.TypeOf(fl.Type)
					if tv == nil { continue }
					base := tv
					if ptr, ok := base.(*types.Pointer); ok { base = ptr.Elem() }
					nm, ok := base.(*types.Named); if !ok { continue }
					if nm.Obj().Pkg() == nil { continue }
					key := nm.Obj().Pkg().Path() + "." + nm.Obj().Name()
					who, ok := satNames[key]; if !ok { continue }
					name := "<embedded>"
					if len(fl.Names) > 0 { name = fl.Names[0].Name }
					pos := p.Fset.Position(fl.Pos())
					fmt.Printf("%s:%d\t%s.%s\t%s\t%s\n", strings.TrimPrefix(pos.Filename, root+"/"), pos.Line, ts.Name.Name, name, key, strings.Join(who, ","))
				}
				return true
			})
		}
	}
}
